/*
 * Serialize encrypted packet to byte buffer for transmission
 * Returns number of bytes written, -1 on error
 */
int crypto_serialize_packet(const encrypted_packet_t *packet,
                            uint8_t *output_buf, size_t buf_size)
{
    size_t total_size;
    size_t offset = 0;

    if (!packet || !output_buf) {
        return -1;
    }

    total_size = DEVICE_ID_SIZE + NONCE_SIZE + TAG_SIZE + 2 + packet->data_len;
    if (total_size > buf_size) {
        return -1;
    }

    memcpy(output_buf + offset, packet->device_id, DEVICE_ID_SIZE);
    offset += DEVICE_ID_SIZE;

    memcpy(output_buf + offset, packet->nonce, NONCE_SIZE);
    offset += NONCE_SIZE;

    memcpy(output_buf + offset, packet->tag, TAG_SIZE);
    offset += TAG_SIZE;

    output_buf[offset++] = (uint8_t)(packet->data_len >> 8);
    output_buf[offset++] = (uint8_t)(packet->data_len);

    memcpy(output_buf + offset, packet->encrypted_data, packet->data_len);
    offset += packet->data_len;

    return (int)offset;
}

/*
 * Deserialize byte buffer back to encrypted packet structure
 * Returns 0 on success, -1 on error
 */
int crypto_deserialize_packet(const uint8_t *input_buf, size_t buf_size,
                              encrypted_packet_t *packet)
{
    size_t offset = 0;
    size_t min_header = DEVICE_ID_SIZE + NONCE_SIZE + TAG_SIZE + 2;

    if (!input_buf || !packet || buf_size < min_header) {
        return -1;
    }

    memcpy(packet->device_id, input_buf + offset, DEVICE_ID_SIZE);
    offset += DEVICE_ID_SIZE;

    memcpy(packet->nonce, input_buf + offset, NONCE_SIZE);
    offset += NONCE_SIZE;

    memcpy(packet->tag, input_buf + offset, TAG_SIZE);
    offset += TAG_SIZE;

    packet->data_len = ((uint16_t)input_buf[offset] << 8) | input_buf[offset + 1];
    offset += 2;

    if (packet->data_len > MAX_PAYLOAD_SIZE || offset + packet->data_len > buf_size) {
        return -1;
    }

    memcpy(packet->encrypted_data, input_buf + offset, packet->data_len);

    return 0;
}

